Create `res://logic/spatial_index.gd`:

```gdscript
class_name SpatialIndex extends RefCounted

const CELL_SIZE: float = 64.0
var buckets: Dictionary = {}  # Vector2i -> Array[int] (entity indices)
var entity_positions: PackedVector2Array = []
var entity_types: PackedInt32Array = []  # enum for enemy/gem/pickup

static func rebuild(index: SpatialIndex, enemies: Array, gems: Array, pickups: Array) -> void:
    index.buckets.clear()
    index.entity_positions.clear()
    index.entity_types.clear()
    # Hash each entity position to cell, store index in bucket
    for i in enemies.size():
        var cell = _pos_to_cell(enemies[i].pos)
        _add_to_bucket(index, cell, i, TYPE_ENEMY)
    # ... repeat for gems, pickups

static func _pos_to_cell(pos: Vector2) -> Vector2i:
    return Vector2i(int(pos.x / CELL_SIZE), int(pos.y / CELL_SIZE))

static func query_radius(index: SpatialIndex, center: Vector2, r: float) -> PackedInt32Array:
    var results: PackedInt32Array = []
    var min_cell = _pos_to_cell(center - Vector2(r, r))
    var max_cell = _pos_to_cell(center + Vector2(r, r))
    for x in range(min_cell.x, max_cell.x + 1):
        for y in range(min_cell.y, max_cell.y + 1):
            var cell = Vector2i(x, y)
            if index.buckets.has(cell):
                for entry in index.buckets[cell]:
                    var pos = index.entity_positions[entry]
                    if center.distance_squared_to(pos) <= r * r:
                        results.append(entry)
    return results

