Create `res://autoload/game_data.gd`:

```gdscript
extends Node

# Preloaded resources
var _weapons: Dictionary = {}
var _enemies: Dictionary = {}
var _passives: Dictionary = {}
var _characters: Dictionary = {}
var _stages: Dictionary = {}
var _level_curve: Array[int] = []

func _ready() -> void:
    _load_weapons()
    _load_enemies()
    _load_passives()
    _load_characters()
    _load_stages()
    _load_level_curve()

func _load_weapons() -> void:
    var dir = DirAccess.open("res://data/weapons/")
    if dir:
        dir.list_dir_begin()
        var file = dir.get_next()
        while file != "":
            if file.ends_with(".tres"):
                var weapon = load("res://data/weapons/" + file) as WeaponDef
                _weapons[weapon.id] = weapon
            file = dir.get_next()

func get_weapon(id: String) -> WeaponDef:
    return _weapons.get(id)

func get_enemy(id: String) -> EnemyDef:
    return _enemies.get(id)

func get_passive(id: String) -> PassiveDef:
    return _passives.get(id)

func get_character(id: String) -> CharacterDef:
    return _characters.get(id)

func get_stage(id: String) -> StageDef:
    return _stages.get(id)

func get_xp_for_level(level: int) -> float:
    if level <= 0 or level > _level_curve.size():
        return 99999.0
    return float(_level_curve[level - 1])

func get_all_weapons() -> Array[WeaponDef]:
    return _weapons.values()

func get_all_passives() -> Array[PassiveDef]:
    return _passives.values()
```

