```gdscript
# res://game/background.gdshader
shader_type canvas_item;
uniform vec2 camera_pos;
uniform sampler2D tile_texture;

void fragment() {
    vec2 uv = UV + camera_pos / 64.0;  // tile size
    COLOR = texture(tile_texture, fract(uv));
}
```

Create `res://ui/pause_screen.tscn` and `res://ui/pause_screen.gd`:

```gdscript
extends Control
class_name PauseScreen

signal resume_requested
signal quit_requested

@onready var resume_btn: Button = $Panel/VBoxContainer/ResumeButton
@onready var quit_btn: Button = $Panel/VBoxContainer/QuitButton

func _ready() -> void:
    hide()
    resume_btn.pressed.connect(_on_resume)
    quit_btn.pressed.connect(_on_quit)

func _input(event: InputEvent) -> void:
    if event.is_action_pressed("pause") and visible:
        _on_resume()
        get_viewport().set_input_as_handled()

func show_pause() -> void:
    show()
    resume_btn.grab_focus()

func _on_resume() -> void:
    hide()
    resume_requested.emit()

func _on_quit() -> void:
    hide()
    quit_requested.emit()
```

