# run_controller.gd additions

@onready var presentation: PresentationLayer = $World/EntityRenderer
@onready var hud: HUD = $UILayer/HUD
@onready var level_up_screen: LevelUpScreen = $UILayer/LevelUpScreen
@onready var pause_screen: PauseScreen = $UILayer/PauseScreen
@onready var death_screen: DeathScreen = $UILayer/DeathScreen
@onready var results_screen: ResultsScreen = $UILayer/ResultsScreen
@onready var main_menu: MainMenu = $UILayer/MainMenu

func _ready() -> void:
    # Connect signals
    level_up_started.connect(level_up_screen.show_offer)
    level_up_screen.option_chosen.connect(on_option_chosen)
    pause_screen.resume_requested.connect(_on_resume)
    pause_screen.quit_requested.connect(_on_quit_to_menu)
    death_screen.revive_requested.connect(_on_revive)
    death_screen.continue_requested.connect(_on_show_results)
    results_screen.done.connect(_on_results_done)
    main_menu.start_game.connect(start_run)
    phase_changed.connect(_on_phase_changed)

    _set_phase(GameState.Phase.TITLE)

func _process(delta: float) -> void:
    if state:
        presentation.sync(state)
        hud.update_from_state(state)

func _on_phase_changed(phase: int) -> void:
    main_menu.visible = phase == GameState.Phase.TITLE
    hud.visible = phase == GameState.Phase.PLAYING or phase == GameState.Phase.PAUSED
    # etc.
